"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import Link from "next/link";
import { Menu, X } from "lucide-react";

const navLinks = [
  { name: "Home", href: "/" },
  { name: "About Us", href: "/about" },
  { name: "Menu", href: "/menu" },
  { name: "Insights", href: "/insights" },
  { name: "Contact", href: "/contact" },
  { name: "Orders", href: "/orders" },
];

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <>
      <motion.nav
        initial={{ y: -100 }}
        animate={{ y: 0 }}
        transition={{ duration: 0.6, ease: "easeOut" }}
        className="fixed top-0 left-0 right-0 z-50 w-full transition-all duration-500"
        style={
          scrolled
            ? { backgroundColor: 'rgba(13, 13, 13, 0.95)', backdropFilter: 'blur(20px)', boxShadow: '0 4px 30px rgba(0,0,0,0.3)', borderBottom: '1px solid rgba(201, 169, 110, 0.1)' }
            : { backgroundColor: 'transparent' }
        }
      >
        <div className="max-w-7xl mx-auto px-6 sm:px-8 lg:px-10">
          <div className="flex items-center justify-between h-24">
            {/* Logo */}
            <Link href="/" className="flex items-center gap-4 group">
              <div className="w-11 h-11 rounded-full flex items-center justify-center group-hover:border-[#C9A96E] transition-colors duration-300" style={{ border: '1px solid rgba(201, 169, 110, 0.6)' }}>
                <span className="text-[#C9A96E] font-serif text-lg font-bold">A</span>
              </div>
              <div>
                <span className="text-[#F5F0EB] font-serif text-xl tracking-wider group-hover:text-[#C9A96E] transition-colors duration-300">
                  Aurora
                </span>
                <span className="block text-[10px] tracking-[0.3em] uppercase -mt-1" style={{ color: 'rgba(201, 169, 110, 0.7)' }}>
                  Dining
                </span>
              </div>
            </Link>

            {/* Desktop links */}
            <div className="hidden lg:flex items-center gap-10">
              {navLinks.map((link) => (
                <Link
                  key={link.name}
                  href={link.href}
                  className="animated-underline text-sm tracking-wider uppercase hover:text-[#C9A96E] transition-colors duration-300"
                  style={{ color: 'rgba(245, 240, 235, 0.8)' }}
                >
                  {link.name}
                </Link>
              ))}
              <Link
                href="/contact"
                className="ml-6 px-7 py-2.5 text-[#C9A96E] text-sm tracking-wider uppercase hover:bg-[#C9A96E] hover:text-[#0D0D0D] transition-all duration-300 rounded"
                style={{ border: '1px solid rgba(201, 169, 110, 0.5)' }}
              >
                Reserve
              </Link>
            </div>

            {/* Mobile toggle */}
            <button
              onClick={() => setMobileOpen(!mobileOpen)}
              className="lg:hidden text-[#F5F0EB] hover:text-[#C9A96E] transition-colors"
            >
              {mobileOpen ? <X size={26} /> : <Menu size={26} />}
            </button>
          </div>
        </div>
      </motion.nav>

      {/* Mobile menu */}
      <AnimatePresence>
        {mobileOpen && (
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            transition={{ duration: 0.3 }}
            className="fixed inset-0 z-40 pt-28 px-10"
            style={{ backgroundColor: 'rgba(13, 13, 13, 0.98)', backdropFilter: 'blur(24px)' }}
          >
            <div className="flex flex-col gap-8">
              {navLinks.map((link, i) => (
                <motion.div
                  key={link.name}
                  initial={{ opacity: 0, x: -30 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: i * 0.08 }}
                >
                  <Link
                    href={link.href}
                    onClick={() => setMobileOpen(false)}
                    className="text-2xl font-serif text-[#F5F0EB] hover:text-[#C9A96E] transition-colors tracking-wider"
                  >
                    {link.name}
                  </Link>
                </motion.div>
              ))}
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.5 }}
                className="mt-8 pt-8"
                style={{ borderTop: '1px solid rgba(201, 169, 110, 0.2)' }}
              >
                <Link
                  href="/contact"
                  onClick={() => setMobileOpen(false)}
                  className="inline-block px-10 py-4 text-[#C9A96E] tracking-wider uppercase hover:bg-[#C9A96E] hover:text-[#0D0D0D] transition-all duration-300"
                  style={{ border: '1px solid #C9A96E' }}
                >
                  Reserve a Table
                </Link>
              </motion.div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}
